// TypeScript: Deploy to AWS Lambda
import { Handler } from "aws-lambda";
import { Agent } from "@anthropic-ai/claude-agent-sdk";

export const handler: Handler = async (event) => {
  const agent = new Agent({
    apiKey: event.apiKey,
    allowedTools: ["read", "write", "bash"]
  });

  const result = await agent.query(event.prompt);
  return { result: result.output };
};

# Python: Deploy to Google Cloud Functions
from claude_agent_sdk import Agent
import functions_framework

agent = Agent(allowed_tools=["read", "write", "bash"])

@functions_framework.http
def main(request):
    prompt = request.json.get("prompt")
    result = agent.query(prompt)
    return {"result": result.output}

// Secure proxy pattern
import { Agent } from "@anthropic-ai/claude-agent-sdk";

// Proxy injects API key, agent doesn't see it
const proxy = createProxy({
  apiUrl: "https://api.your-company.com/claude",
  apiKey: process.env.ANTHROPIC_API_KEY
});

export async function handleRequest(prompt: string) {
  const agent = new Agent({
    // Agent uses proxy, not direct API key
    apiUrl: proxy.apiUrl,
    allowedTools: ["read", "write", "bash"]
  });

  return agent.query(prompt);
}
